import { Component, h, Prop, Element, Event, EventEmitter, State } from '@stencil/core';
import { loadIconContent } from '../../utils/icon-registry';

@Component({
  tag: 'wdpr-user-profile',
  shadow: true,
  styleUrl: 'wdpr-user-profile.css',
})
export class WdprUserProfile {
  @Element() el: HTMLElement;

  @Prop() userName: string;
  @Prop() hubId: string;
  @Prop() initials: string;
  @Prop() imageSrc?: string;
  @Prop() disabled: boolean = false;
  @Prop() statusMessage?: string;
  @Prop() settingsHref: string = '#';
  @Prop() showNotification: boolean = false;
  @Prop() notificationLabel: string = 'You have new notifications';

  @State() _badgeSvg: string = '';
  @State() _hasActionSlotContent: boolean = false;

  @Event({ eventName: 'wdprSignoutButtonClicked' }) signOutClicked: EventEmitter<void>;
  @Event({ eventName: 'wdprUserSettingsClicked' }) userSettingsClicked: EventEmitter<void>;

  componentDidLoad() {
    const slot = this.el.shadowRoot?.querySelector('slot[name="action"]') as HTMLSlotElement;

    if (slot) {
      const updateSlot = () => {
        this._hasActionSlotContent = slot.assignedNodes({ flatten: true }).length > 0;
      };

      slot.addEventListener('slotchange', updateSlot);
      updateSlot();
    }
  }

  async componentWillLoad() {
    const svg = await loadIconContent('user-profile-badge');
    if (svg) {
      this._badgeSvg = svg
        .replace(/fill="#[0-9A-Fa-f]{6}"/g, 'fill="currentColor"')
        .replace('<svg', '<svg class="absolute inset-0 w-full h-full" aria-hidden="true"');
    }
  }

  private _renderAvatar() {
    if (this.imageSrc) {
      return (
        <div class="relative flex items-center justify-center mb-200 w-[120px] h-[120px]">
          <wdpr-media
            src={this.imageSrc}
            alt={this.userName}
            aspect="square"
            shape="round"
            objectFit="cover"
            class="w-full h-full"
          />
        </div>
      );
    }

    return (
      <div class="relative mb-200 w-32 h-[120px] text-text-neutral-extra-dark">
        <div innerHTML={this._badgeSvg} />
        <div class="absolute inset-0 flex items-center justify-center pt-150">
          <span class="uppercase font-black text-[36px] leading-[54px]">
            {this.initials?.substring(0, 2)}
          </span>
        </div>
      </div>
    );
  }

  private _renderIdentity() {
    return (
      <div class="mb-200 flex flex-col items-center text-center">
        <h2 class="text-[20px] font-black text-text-heading m-000 p-000 leading-tight">
          {this.userName}
        </h2>
        <span class="text-[14px] text-text-body uppercase mt-025">
          {this.hubId}
        </span>
      </div>
    );
  }

  private _handleSignOutClick = () => {
    if (!this.disabled) {
      this.signOutClicked.emit();
    }
  };

  private _handleUserSettingsClick = () => {
    if (!this.disabled) {
      this.userSettingsClicked.emit();
    }
  };

  render() {
    return (
      <div class="bg-surface-default elevation-small-soft rounded-200 p-300 w-[288px] md:w-[320px]">
        <div class="flex flex-col items-center">
          {this._renderAvatar()}
          {this._renderIdentity()}
          <div
            class={`flex items-center justify-center gap-050${this.disabled ? ' opacity-50' : ''}${this._hasActionSlotContent ? ' mb-100' : ''}`}
            aria-disabled={this.disabled ? 'true' : undefined}
            inert={this.disabled || undefined}
          >
            <slot name="action" />
            {this.showNotification && this._hasActionSlotContent && (
              <wdpr-notification-indicator
                size="small"
                type="alert"
                decorative={false}
                a11y-label={this.notificationLabel}
              />
            )}
          </div>
          <div class="mb-100">
            <wdpr-button
              variant="text"
              disabled={this.disabled}
              onClick={this._handleUserSettingsClick}
              size="medium"
            >
              User Settings
            </wdpr-button>
          </div>

          {this.statusMessage && (
            <div class="mb-200 w-full flex justify-center">
              <wdpr-inline-message variant="informational" size="small">{this.statusMessage}</wdpr-inline-message>
            </div>
          )}

          <div class="w-full">
            <wdpr-button onClick={this._handleSignOutClick} variant="tertiary" disabled={this.disabled} display="block" size="medium">
              Sign Out
            </wdpr-button>
          </div>

        </div>
      </div>
    );
  }
}